import { Link } from "react-router-dom";

function ListProperty() {
    return(
        <div>
            <section className="hero">
                <h1>List Property</h1>
                <Link to="/">Click to Login</Link>
                <div>
                   <Link to="/Register">Go to Register</Link>
                </div>
            </section>
           </div>
    );


}


export default ListProperty;
